/**
 * Tests for UndoRedoManager and Command Factories
 *
 * @module __tests__/unit/lib/editor/undo-redo.test
 */

import {
  UndoRedoManager,
  createCommand,
  addSlideCommand,
  removeSlideCommand,
  reorderSlidesCommand,
  addElementCommand,
  removeElementCommand,
  moveElementCommand,
  resizeElementCommand,
  editTextCommand,
  batchCommand,
  type UndoableCommand,
  type StateWithSlides,
  type StateWithElements,
} from '@/lib/editor/undo-redo';

// ============================================================================
// Test State Types
// ============================================================================

interface TestState extends StateWithSlides, StateWithElements {
  title: string;
}

function createTestState(overrides?: Partial<TestState>): TestState {
  return {
    title: 'Test Project',
    slides: [
      { id: 'slide-1', content: 'Slide 1' },
      { id: 'slide-2', content: 'Slide 2' },
      { id: 'slide-3', content: 'Slide 3' },
    ],
    elements: [
      { id: 'el-1', type: 'text', text: 'Hello', x: 0, y: 0, width: 100, height: 50 },
      { id: 'el-2', type: 'image', x: 100, y: 100, width: 200, height: 150 },
    ],
    ...overrides,
  };
}

// ============================================================================
// UndoRedoManager Tests
// ============================================================================

describe('UndoRedoManager', () => {
  let manager: UndoRedoManager<TestState>;
  let initialState: TestState;

  beforeEach(() => {
    manager = new UndoRedoManager<TestState>({ maxHistorySize: 50 });
    initialState = createTestState();
  });

  describe('execute', () => {
    it('should execute a command and return new state', () => {
      const cmd = createCommand<TestState>(
        'custom',
        'Change title',
        (state) => ({ ...state, title: 'New Title' }),
        (state) => ({ ...state, title: 'Test Project' }),
      );

      const newState = manager.execute(cmd, initialState);
      expect(newState.title).toBe('New Title');
    });

    it('should track command in undo stack', () => {
      const cmd = createCommand<TestState>(
        'custom',
        'Change title',
        (state) => ({ ...state, title: 'Changed' }),
        (state) => ({ ...state, title: initialState.title }),
      );

      manager.execute(cmd, initialState);
      const state = manager.getState();

      expect(state.canUndo).toBe(true);
      expect(state.undoStackSize).toBe(1);
      expect(state.undoDescription).toBe('Change title');
    });

    it('should clear redo stack after new execute', () => {
      const cmd1 = createCommand<TestState>(
        'custom', 'Cmd 1',
        (state) => ({ ...state, title: 'One' }),
        (state) => ({ ...state, title: 'Test Project' }),
      );
      const cmd2 = createCommand<TestState>(
        'custom', 'Cmd 2',
        (state) => ({ ...state, title: 'Two' }),
        (state) => ({ ...state, title: 'One' }),
      );

      // Execute two commands
      let state = manager.execute(cmd1, initialState);
      state = manager.execute(cmd2, state);

      // Undo one
      state = manager.undo(state);
      expect(manager.getState().canRedo).toBe(true);

      // Execute new command — should clear redo
      const cmd3 = createCommand<TestState>(
        'custom', 'Cmd 3',
        (s) => ({ ...s, title: 'Three' }),
        (s) => ({ ...s, title: 'One' }),
      );
      manager.execute(cmd3, state);

      expect(manager.getState().canRedo).toBe(false);
      expect(manager.getState().redoStackSize).toBe(0);
    });

    it('should respect maxHistorySize', () => {
      const smallManager = new UndoRedoManager<TestState>({ maxHistorySize: 3 });
      let state = initialState;

      for (let i = 0; i < 10; i++) {
        const cmd = createCommand<TestState>(
          'custom', `Cmd ${i}`,
          (s) => ({ ...s, title: `Title ${i}` }),
          (s) => ({ ...s, title: `Title ${i - 1}` }),
        );
        state = smallManager.execute(cmd, state);
      }

      expect(smallManager.getState().undoStackSize).toBe(3);
    });
  });

  describe('undo', () => {
    it('should undo the last command', () => {
      const cmd = createCommand<TestState>(
        'custom', 'Change title',
        (state) => ({ ...state, title: 'Changed' }),
        (state) => ({ ...state, title: 'Test Project' }),
      );

      let state = manager.execute(cmd, initialState);
      expect(state.title).toBe('Changed');

      state = manager.undo(state);
      expect(state.title).toBe('Test Project');
    });

    it('should return same state when nothing to undo', () => {
      const state = manager.undo(initialState);
      expect(state).toBe(initialState);
    });

    it('should move command to redo stack', () => {
      const cmd = createCommand<TestState>(
        'custom', 'Change',
        (state) => ({ ...state, title: 'X' }),
        (state) => ({ ...state, title: 'Test Project' }),
      );

      let state = manager.execute(cmd, initialState);
      state = manager.undo(state);

      const managerState = manager.getState();
      expect(managerState.canRedo).toBe(true);
      expect(managerState.redoDescription).toBe('Change');
      expect(managerState.canUndo).toBe(false);
    });

    it('should support multiple undos', () => {
      const cmd1 = createCommand<TestState>(
        'custom', 'First',
        (s) => ({ ...s, title: 'A' }),
        (s) => ({ ...s, title: 'Test Project' }),
      );
      const cmd2 = createCommand<TestState>(
        'custom', 'Second',
        (s) => ({ ...s, title: 'B' }),
        (s) => ({ ...s, title: 'A' }),
      );

      let state = manager.execute(cmd1, initialState);
      state = manager.execute(cmd2, state);
      expect(state.title).toBe('B');

      state = manager.undo(state);
      expect(state.title).toBe('A');

      state = manager.undo(state);
      expect(state.title).toBe('Test Project');
    });
  });

  describe('redo', () => {
    it('should redo an undone command', () => {
      const cmd = createCommand<TestState>(
        'custom', 'Change',
        (s) => ({ ...s, title: 'Changed' }),
        (s) => ({ ...s, title: 'Test Project' }),
      );

      let state = manager.execute(cmd, initialState);
      state = manager.undo(state);
      expect(state.title).toBe('Test Project');

      state = manager.redo(state);
      expect(state.title).toBe('Changed');
    });

    it('should return same state when nothing to redo', () => {
      const state = manager.redo(initialState);
      expect(state).toBe(initialState);
    });

    it('should support undo → redo → undo cycle', () => {
      const cmd = createCommand<TestState>(
        'custom', 'Cycle',
        (s) => ({ ...s, title: 'Cycled' }),
        (s) => ({ ...s, title: 'Test Project' }),
      );

      let state = manager.execute(cmd, initialState);
      state = manager.undo(state);
      state = manager.redo(state);
      expect(state.title).toBe('Cycled');

      state = manager.undo(state);
      expect(state.title).toBe('Test Project');
    });
  });

  describe('clear', () => {
    it('should clear both undo and redo stacks', () => {
      const cmd = createCommand<TestState>(
        'custom', 'Test',
        (s) => ({ ...s, title: 'X' }),
        (s) => ({ ...s, title: 'Y' }),
      );

      manager.execute(cmd, initialState);
      manager.clear();

      const state = manager.getState();
      expect(state.canUndo).toBe(false);
      expect(state.canRedo).toBe(false);
      expect(state.historySize).toBe(0);
    });
  });

  describe('getState', () => {
    it('should return correct initial state', () => {
      const state = manager.getState();
      expect(state.canUndo).toBe(false);
      expect(state.canRedo).toBe(false);
      expect(state.undoDescription).toBeNull();
      expect(state.redoDescription).toBeNull();
      expect(state.historySize).toBe(0);
    });
  });

  describe('getUndoHistory', () => {
    it('should return list of executed commands', () => {
      const cmd1 = createCommand<TestState>(
        'custom', 'First change',
        (s) => ({ ...s, title: 'A' }),
        (s) => ({ ...s, title: 'B' }),
      );
      const cmd2 = createCommand<TestState>(
        'text:edit', 'Edit text',
        (s) => ({ ...s, title: 'C' }),
        (s) => ({ ...s, title: 'D' }),
      );

      manager.execute(cmd1, initialState);
      manager.execute(cmd2, initialState);

      const history = manager.getUndoHistory();
      expect(history).toHaveLength(2);
      expect(history[0].description).toBe('First change');
      expect(history[0].type).toBe('custom');
      expect(history[1].description).toBe('Edit text');
      expect(history[1].type).toBe('text:edit');
    });
  });

  describe('onChange callback', () => {
    it('should fire after execute', () => {
      const onChange = jest.fn();
      const mgr = new UndoRedoManager<TestState>({ onChange });

      const cmd = createCommand<TestState>(
        'custom', 'Test',
        (s) => ({ ...s, title: 'X' }),
        (s) => ({ ...s, title: 'Y' }),
      );

      mgr.execute(cmd, initialState);
      expect(onChange).toHaveBeenCalledTimes(1);
      expect(onChange).toHaveBeenCalledWith(expect.objectContaining({ canUndo: true }));
    });

    it('should fire after undo', () => {
      const onChange = jest.fn();
      const mgr = new UndoRedoManager<TestState>({ onChange });

      const cmd = createCommand<TestState>(
        'custom', 'Test',
        (s) => ({ ...s, title: 'X' }),
        (s) => ({ ...s, title: 'Y' }),
      );

      const state = mgr.execute(cmd, initialState);
      onChange.mockClear();

      mgr.undo(state);
      expect(onChange).toHaveBeenCalledTimes(1);
    });

    it('should fire after clear', () => {
      const onChange = jest.fn();
      const mgr = new UndoRedoManager<TestState>({ onChange });

      mgr.clear();
      expect(onChange).toHaveBeenCalledTimes(1);
    });
  });
});

// ============================================================================
// Slide Command Tests
// ============================================================================

describe('Slide Commands', () => {
  let state: TestState;

  beforeEach(() => {
    state = createTestState();
  });

  describe('addSlideCommand', () => {
    it('should add a slide at the end', () => {
      const cmd = addSlideCommand<TestState>({ id: 'slide-4', content: 'New' });
      const newState = cmd.execute(state);

      expect(newState.slides).toHaveLength(4);
      expect(newState.slides[3].id).toBe('slide-4');
    });

    it('should add a slide at a specific index', () => {
      const cmd = addSlideCommand<TestState>({ id: 'slide-new', content: 'Inserted' }, 1);
      const newState = cmd.execute(state);

      expect(newState.slides).toHaveLength(4);
      expect(newState.slides[1].id).toBe('slide-new');
      expect(newState.slides[2].id).toBe('slide-2');
    });

    it('should undo adding a slide', () => {
      const cmd = addSlideCommand<TestState>({ id: 'slide-4', content: 'New' });
      const added = cmd.execute(state);
      const undone = cmd.undo(added);

      expect(undone.slides).toHaveLength(3);
      expect(undone.slides.find(s => s.id === 'slide-4')).toBeUndefined();
    });
  });

  describe('removeSlideCommand', () => {
    it('should remove a slide by ID', () => {
      const cmd = removeSlideCommand<TestState>('slide-2');
      const newState = cmd.execute(state);

      expect(newState.slides).toHaveLength(2);
      expect(newState.slides.find(s => s.id === 'slide-2')).toBeUndefined();
    });

    it('should undo removing a slide (restoring at original position)', () => {
      const cmd = removeSlideCommand<TestState>('slide-2');
      const removed = cmd.execute(state);
      const restored = cmd.undo(removed);

      expect(restored.slides).toHaveLength(3);
      expect(restored.slides[1].id).toBe('slide-2');
    });

    it('should handle removing non-existent slide gracefully', () => {
      const cmd = removeSlideCommand<TestState>('nonexistent');
      const newState = cmd.execute(state);
      expect(newState.slides).toHaveLength(3);
    });
  });

  describe('reorderSlidesCommand', () => {
    it('should move slide from one position to another', () => {
      const cmd = reorderSlidesCommand<TestState>(0, 2);
      const newState = cmd.execute(state);

      expect(newState.slides[0].id).toBe('slide-2');
      expect(newState.slides[1].id).toBe('slide-3');
      expect(newState.slides[2].id).toBe('slide-1');
    });

    it('should undo reorder', () => {
      const cmd = reorderSlidesCommand<TestState>(0, 2);
      const reordered = cmd.execute(state);
      const undone = cmd.undo(reordered);

      expect(undone.slides[0].id).toBe('slide-1');
      expect(undone.slides[1].id).toBe('slide-2');
      expect(undone.slides[2].id).toBe('slide-3');
    });
  });
});

// ============================================================================
// Element Command Tests
// ============================================================================

describe('Element Commands', () => {
  let state: TestState;

  beforeEach(() => {
    state = createTestState();
  });

  describe('addElementCommand', () => {
    it('should add an element', () => {
      const cmd = addElementCommand<TestState>({ id: 'el-3', type: 'shape' });
      const newState = cmd.execute(state);

      expect(newState.elements).toHaveLength(3);
      expect(newState.elements[2].id).toBe('el-3');
    });

    it('should undo adding an element', () => {
      const cmd = addElementCommand<TestState>({ id: 'el-3', type: 'shape' });
      const added = cmd.execute(state);
      const undone = cmd.undo(added);

      expect(undone.elements).toHaveLength(2);
    });
  });

  describe('removeElementCommand', () => {
    it('should remove an element', () => {
      const cmd = removeElementCommand<TestState>('el-1');
      const newState = cmd.execute(state);

      expect(newState.elements).toHaveLength(1);
      expect(newState.elements[0].id).toBe('el-2');
    });

    it('should undo removing an element (restore at original position)', () => {
      const cmd = removeElementCommand<TestState>('el-1');
      const removed = cmd.execute(state);
      const undone = cmd.undo(removed);

      expect(undone.elements).toHaveLength(2);
      expect(undone.elements[0].id).toBe('el-1');
    });
  });

  describe('moveElementCommand', () => {
    it('should move element to new position', () => {
      const cmd = moveElementCommand<TestState>('el-1', 0, 0, 50, 75);
      const newState = cmd.execute(state);

      const movedEl = newState.elements.find(e => e.id === 'el-1');
      expect(movedEl?.x).toBe(50);
      expect(movedEl?.y).toBe(75);
    });

    it('should undo move element', () => {
      const cmd = moveElementCommand<TestState>('el-1', 0, 0, 50, 75);
      const moved = cmd.execute(state);
      const undone = cmd.undo(moved);

      const el = undone.elements.find(e => e.id === 'el-1');
      expect(el?.x).toBe(0);
      expect(el?.y).toBe(0);
    });
  });

  describe('resizeElementCommand', () => {
    it('should resize element', () => {
      const cmd = resizeElementCommand<TestState>(
        'el-1',
        { width: 100, height: 50 },
        { width: 200, height: 100 },
      );
      const newState = cmd.execute(state);

      const el = newState.elements.find(e => e.id === 'el-1');
      expect(el?.width).toBe(200);
      expect(el?.height).toBe(100);
    });

    it('should undo resize element', () => {
      const cmd = resizeElementCommand<TestState>(
        'el-1',
        { width: 100, height: 50 },
        { width: 200, height: 100 },
      );
      const resized = cmd.execute(state);
      const undone = cmd.undo(resized);

      const el = undone.elements.find(e => e.id === 'el-1');
      expect(el?.width).toBe(100);
      expect(el?.height).toBe(50);
    });
  });
});

